class Solution:
    def nthUglyNumber(self, n):
        import heapq
        heap = [1]
        seen = {1}
        val = 1
        for _ in range(n):
            val = heapq.heappop(heap)
            for p in (2, 3, 5):
                nxt = val * p
                if nxt not in seen:
                    seen.add(nxt)
                    heapq.heappush(heap, nxt)
        return val

