class Solution:
    def nthUglyNumber(self, n):
        seq = [1] * n
        i2 = i3 = i5 = 0
        for i in range(1, n):
            c2, c3, c5 = seq[i2] * 2, seq[i3] * 3, seq[i5] * 5
            nxt = min(c2, c3, c5)
            seq[i] = nxt
            if nxt == c2:
                i2 += 1
            if nxt == c3:
                i3 += 1
            if nxt == c5:
                i5 += 1
        return seq[n - 1]

