var nthUglyNumber = function(n) {
    const seq = new Array(n).fill(1);
    let i2 = 0, i3 = 0, i5 = 0;
    for (let i = 1; i < n; i++) {
        const c2 = seq[i2] * 2, c3 = seq[i3] * 3, c5 = seq[i5] * 5;
        const nxt = Math.min(c2, c3, c5);
        seq[i] = nxt;
        if (nxt === c2) i2++;
        if (nxt === c3) i3++;
        if (nxt === c5) i5++;
    }
    return seq[n - 1];
};
